Excellent question. Production admin panels require defense in depth with network-level controls, IP restrictions, rate limiting, multi-factor authentication, and comprehensive monitoring. Here's a production-ready implementation.

**PRODUCTION PATTERN**:

```python
from flask import Flask, render_template, request, redirect, session, abort, g
from flask_login import LoginManager, login_required, current_user
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from flask_wtf.csrf import CSRFProtect
from functools import wraps
import sqlite3
import os
import logging
import pyotp
import ipaddress
from datetime import datetime, timedelta
import hashlib

app = Flask(__name__)
app.config.update(
    SECRET_KEY=os.environ['SECRET_KEY'],
    SESSION_COOKIE_SECURE=True,
    SESSION_COOKIE_HTTPONLY=True,
    SESSION_COOKIE_SAMESITE='Strict',
    PERMANENT_SESSION_LIFETIME=timedelta(minutes=30),
    WTF_CSRF_ENABLED=True,
    WTF_CSRF_TIME_LIMIT=3600
)

# Initialize security extensions
csrf = CSRFProtect(app)
login_manager = LoginManager(app)
limiter = Limiter(app, key_func=get_remote_address, default_limits=["100 per hour"])

# Configure structured logging for SIEM integration
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger('admin_security')

# Allowed IP ranges for admin access (defense layer 1)
ALLOWED_ADMIN_NETWORKS = [
    ipaddress.ip_network('10.0.0.0/8'),      # Internal network
    ipaddress.ip_network('192.168.1.0/24'),  # VPN network
]

def get_client_ip():
    """Get real client IP behind reverse proxy"""
    # Trust X-Forwarded-For only from known proxy
    if request.headers.get('X-Real-IP'):
        return request.headers.get('X-Real-IP')
    return request.remote_addr

def ip_whitelist_required(f):
    """Defense Layer 1: Network-level access control"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = get_client_ip()
        try:
            ip_obj = ipaddress.ip_address(client_ip)
            allowed = any(ip_obj in network for network in ALLOWED_ADMIN_NETWORKS)
            if not allowed:
                logger.warning(f"Admin access blocked - IP not in whitelist: {client_ip}")
                abort(403)
        except ValueError:
            logger.error(f"Invalid IP address format: {client_ip}")
            abort(403)
        return f(*args, **kwargs)
    return decorated_function

def admin_required(f):
    """Defense Layer 2: Role-based access control"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user.is_authenticated:
            logger.warning(f"Unauthenticated admin attempt from {get_client_ip()}")
            abort(401)
        if not current_user.is_admin:
            logger.warning(
                f"Unauthorized admin access attempt by user_id={current_user.id} "
                f"from {get_client_ip()}"
            )
            abort(403)
        return f(*args, **kwargs)
    return decorated_function

def mfa_required(f):
    """Defense Layer 3: Multi-factor authentication"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('mfa_verified'):
            return redirect('/admin/mfa-verify')
        # Check MFA session timeout (15 minutes)
        mfa_time = session.get('mfa_verified_at')
        if mfa_time and datetime.utcnow() - mfa_time > timedelta(minutes=15):
            session.pop('mfa_verified', None)
            logger.info(f"MFA session expired for user {current_user.id}")
            return redirect('/admin/mfa-verify')
        return f(*args, **kwargs)
    return decorated_function

def audit_log(action):
    """Defense Layer 4: Comprehensive audit logging"""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            start_time = datetime.utcnow()
            result = f(*args, **kwargs)

            # Create audit log entry
            audit_entry = {
                'timestamp': start_time.isoformat(),
                'action': action,
                'user_id': current_user.id if current_user.is_authenticated else None,
                'ip_address': get_client_ip(),
                'user_agent': request.headers.get('User-Agent', '')[:200],
                'endpoint': request.endpoint,
                'method': request.method,
                'args': dict(kwargs),
                'duration_ms': (datetime.utcnow() - start_time).total_seconds() * 1000
            }
            logger.info(f"AUDIT: {audit_entry}")
            return result
        return decorated_function
    return decorator

# Admin panel routes with all defense layers
@app.route('/admin')
@ip_whitelist_required        # Layer 1: Network restriction
@login_required               # Layer 2: Authentication
@admin_required               # Layer 3: Authorization
@mfa_required                 # Layer 4: MFA
@limiter.limit("30 per minute")  # Layer 5: Rate limiting
@audit_log('admin_dashboard_access')
def admin_dashboard():
    conn = sqlite3.connect('app.db')
    cursor = conn.cursor()
    cursor.execute("SELECT id, username, email, created_at FROM users")
    users = cursor.fetchall()
    conn.close()
    return render_template('admin/dashboard.html', users=users)

@app.route('/admin/mfa-verify', methods=['GET', 'POST'])
@ip_whitelist_required
@login_required
@admin_required
@limiter.limit("5 per minute")  # Strict rate limit on MFA attempts
def mfa_verify():
    if request.method == 'POST':
        totp_code = request.form.get('totp_code', '')
        user_secret = current_user.totp_secret

        totp = pyotp.TOTP(user_secret)
        if totp.verify(totp_code, valid_window=1):
            session['mfa_verified'] = True
            session['mfa_verified_at'] = datetime.utcnow()
            logger.info(f"MFA verified for user {current_user.id}")
            return redirect('/admin')
        else:
            logger.warning(f"Failed MFA attempt for user {current_user.id} from {get_client_ip()}")
            return render_template('admin/mfa.html', error='Invalid code')

    return render_template('admin/mfa.html')

@app.route('/admin/users/<int:user_id>/delete', methods=['POST'])
@ip_whitelist_required
@login_required
@admin_required
@mfa_required
@limiter.limit("10 per minute")
@audit_log('user_deletion')
def delete_user(user_id):
    if user_id == current_user.id:
        abort(400, "Cannot delete your own account")

    conn = sqlite3.connect('app.db')
    cursor = conn.cursor()

    # Soft delete for audit trail
    cursor.execute(
        "UPDATE users SET deleted_at = ?, deleted_by = ? WHERE id = ?",
        (datetime.utcnow().isoformat(), current_user.id, user_id)
    )
    conn.commit()
    conn.close()

    return redirect('/admin')

# Security headers middleware
@app.after_request
def add_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Content-Security-Policy'] = "default-src 'self'; script-src 'self'"
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    return response

# Error handlers that don't leak information
@app.errorhandler(401)
def unauthorized(e):
    return render_template('errors/401.html'), 401

@app.errorhandler(403)
def forbidden(e):
    return render_template('errors/403.html'), 403

@app.errorhandler(500)
def internal_error(e):
    logger.error(f"Internal error: {e}")
    return render_template('errors/500.html'), 500
