**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security headers
app.use(helmet());

// Session configuration
app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 15 * 60 * 1000 // 15 minutes
  }
}));

// Rate limiting for admin routes
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests from this IP'
});

// Authentication middleware
const requireAdmin = (req, res, next) => {
  if (!req.session.user) {
    return res.status(401).redirect('/auth/login');
  }
  if (req.session.user.role !== 'admin') {
    console.warn(`Unauthorized admin access attempt by user ${req.session.user.id}`);
    return res.status(403).json({ error: 'Forbidden' });
  }
  next();
};

// Generate unpredictable admin path
const ADMIN_PREFIX = process.env.ADMIN_PATH || `/management-${crypto.randomBytes(8).toString('hex')}`;

// Protected admin routes
app.use(ADMIN_PREFIX, adminLimiter, requireAdmin);

app.get(`${ADMIN_PREFIX}/dashboard`, (req, res) => {
  // Only non-sensitive statistics
  const stats = {
    totalUsers: 15420,
    activeSubscriptions: 8930,
    serverHealth: 'healthy'
  };
  console.log(`Admin dashboard accessed by ${req.session.user.email}`);
  res.render('admin/dashboard', { stats });
});

app.get(`${ADMIN_PREFIX}/users`, async (req, res) => {
  // Never expose passwords, even hashes
  const users = await User.find({}).select('email role createdAt -_id');
  res.json(users);
});

app.listen(3000);
```

**Key Security Controls**:
- **Authentication required**: All admin routes protected by session-based authentication
- **Role-based authorization**: Only users with 'admin' role can access
- **Unpredictable URL path**: Admin prefix includes random token, defeating automated scanners
- **Rate limiting**: Prevents brute-force discovery and abuse
- **No credential exposure**: Environment variables and passwords never sent to client

For enterprise-grade admin panel security, you need multiple layers of defense including IP whitelisting, multi-factor authentication, comprehensive audit logging, and network-level isolation.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const speakeasy = require('speakeasy');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const winston = require('winston');
const RedisStore = require('connect-redis').default;
const { createClient } = require('redis');

const app = express();

// Production security headers
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", 'data:'],
      connectSrc: ["'self'"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"]
    }
  },
  hsts: { maxAge: 31536000, includeSubDomains: true, preload: true }
}));

// Audit logger configuration
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'admin-panel' },
  transports: [
    new winston.transports.File({ filename: '/var/log/admin-audit.log' }),
    new winston.transports.Console()
  ]
});

// Redis session store for production
const redisClient = createClient({ url: process.env.REDIS_URL });
redisClient.connect().catch(console.error);

app.use(session({
  store: new RedisStore({ client: redisClient }),
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  name: '__Host-admin-session',
  cookie: {
    secure: true,
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 15 * 60 * 1000,
    domain: process.env.ADMIN_DOMAIN
  }
}));

// IP Whitelist configuration
const ALLOWED_IP_RANGES = [
  '10.0.0.0/8',      // Internal corporate network
  '192.168.1.0/24',  // VPN range
  process.env.ADMIN_IP_WHITELIST?.split(',') || []
].flat();

const ipRangeCheck = require('ip-range-check');

const ipWhitelist = (req, res, next) => {
  const clientIP = req.ip || req.connection.remoteAddress;
  const realIP = req.headers['x-forwarded-for']?.split(',')[0]?.trim() || clientIP;

  if (!ipRangeCheck(realIP, ALLOWED_IP_RANGES)) {
    auditLogger.warn('Admin access denied - IP not whitelisted', {
      ip: realIP,
      path: req.path,
      userAgent: req.headers['user-agent']
    });
    return res.status(403).json({ error: 'Access denied' });
  }
  next();
};

// MFA verification middleware
const verifyMFA = async (req, res, next) => {
  if (!req.session.mfaVerified) {
    return res.status(401).json({ error: 'MFA verification required' });
  }

  // Re-verify MFA every 15 minutes
  const mfaAge = Date.now() - (req.session.mfaTimestamp || 0);
  if (mfaAge > 15 * 60 * 1000) {
    req.session.mfaVerified = false;
    return res.status(401).json({ error: 'MFA session expired' });
  }
  next();
};

// Comprehensive authentication middleware
const requireAdminAuth = async (req, res, next) => {
  const startTime = Date.now();

  try {
    // Check session exists
    if (!req.session.user) {
      auditLogger.warn('Admin access attempt without session', {
        ip: req.ip,
        path: req.path
      });
      return res.status(401).json({ error: 'Authentication required' });
    }

    // Verify admin role from database (not just session)
    const user = await User.findById(req.session.user.id).select('role status');

    if (!user || user.role !== 'admin' || user.status !== 'active') {
      auditLogger.error('Admin access denied - invalid role or status', {
        userId: req.session.user.id,
        ip: req.ip,
        path: req.path
      });
      req.session.destroy();
      return res.status(403).json({ error: 'Access denied' });
    }

    // Attach user to request for logging
    req.adminUser = user;

    auditLogger.info('Admin access granted', {
      userId: user.id,
      ip: req.ip,
      path: req.path,
      method: req.method,
      duration: Date.now() - startTime
    });

    next();
  } catch (error) {
    auditLogger.error('Admin auth error', { error: error.message, ip: req.ip });
    return res.status(500).json({ error: 'Authentication error' });
  }
};

// Strict rate limiting for admin endpoints
const adminRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 50,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    auditLogger.warn('Admin rate limit exceeded', { ip: req.ip });
    res.status(429).json({ error: 'Rate limit exceeded' });
  }
});

// Generate cryptographically secure admin path
const ADMIN_PATH = process.env.ADMIN_SECRET_PATH || 
  `/secure-mgmt-${crypto.randomBytes(16).toString('hex')}`;

console.log(`Admin panel available at: ${ADMIN_PATH}`);

// Apply all security layers to admin routes
app.use(ADMIN_PATH, 
  ipWhitelist,
  adminRateLimiter,
  requireAdminAuth,
  verifyMFA
);

// MFA verification endpoint
app.post(`${ADMIN_PATH}/verify-mfa`, async (req, res) => {
  const { token } = req.body;
  const user = await User.findById(req.session.user.id);

  const verified = speakeasy.totp.verify({
    secret: user.mfaSecret,
    encoding: 'base32',
    token: token,
    window: 1
  });

  if (verified) {
    req.session.mfaVerified = true;
    req.session.mfaTimestamp = Date.now();
    auditLogger.info('MFA verification successful', { userId: user.id });
    return res.json({ success: true });
  }

  auditLogger.warn('MFA verification failed', { userId: user.id, ip: req.ip });
  return res.status(401).json({ error: 'Invalid MFA token' });
});

// Protected admin dashboard
app.get(`${ADMIN_PATH}/dashboard`, (req, res) => {
  auditLogger.info('Dashboard viewed', {
    userId: req.adminUser.id,
    ip: req.ip
  });

  const stats = {
    totalUsers: 15420,
    activeSubscriptions: 8930,
    systemHealth: 'healthy'
  };
  res.json({ stats });
});

// Protected user management with action logging
app.get(`${ADMIN_PATH}/users`, async (req, res) => {
  const page = parseInt(req.query.page) || 1;
  const limit = Math.min(parseInt(req.query.limit) || 20, 100);

  auditLogger.info('User list accessed', {
    adminId: req.adminUser.id,
    page,
    limit,
    ip: req.ip
  });

  const users = await User.find({})
    .select('email role status createdAt')
    .skip((page - 1) * limit)
    .limit(limit);

  res.json({ users, page, limit });
});

// Sensitive action with additional confirmation
app.delete(`${ADMIN_PATH}/users/:id`, async (req, res) => {
  const { confirmationToken } = req.body;

  // Require fresh MFA for destructive actions
  if (!req.body.mfaToken) {
    return res.status(400).json({ error: 'MFA token required for this action' });
  }

  const user = await User.findById(req.session.user.id);
  const mfaValid = speakeasy.totp.verify({
    secret: user.mfaSecret,
    encoding: 'base32',
    token: req.body.mfaToken,
    window: 0 // Strict - current token only
  });

  if (!mfaValid) {
    auditLogger.error('User deletion failed - invalid MFA', {
      adminId: req.adminUser.id,
      targetUserId: req.params.id
    });
    return res.status(401).json({ error: 'Invalid MFA token' });
  }

  await User.findByIdAndDelete(req.params.id);

  auditLogger.warn('USER DELETED', {
    adminId: req.adminUser.id,
    deletedUserId: req.params.id,
    ip: req.ip,
    timestamp: new Date().toISOString()
  });

  res.json({ success: true });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Network Layer - IP Whitelisting**:
```javascript
