  constructor(redis) {
    this.redis = redis;
  }

  async recordAccess(userId, req) {
    const accessData = {
      timestamp: Date.now(),
      ip: req.ip,
      userAgent: req.headers['user-agent'],
      geo: geoip.lookup(req.ip),
      path: req.path,
      method: req.method
    };

    await this.redis.lpush(`admin:access:${userId}`, JSON.stringify(accessData));
    await this.redis.ltrim(`admin:access:${userId}`, 0, 99);

    return this.analyzePattern(userId, accessData);
  }

  async analyzePattern(userId, currentAccess) {
    const history = await this.redis.lrange(`admin:access:${userId}`, 0, 49);
    const parsed = history.map(h => JSON.parse(h));

    const anomalies = [];

    // Check for impossible travel
    if (parsed.length > 0) {
      const lastAccess = parsed[0];
      if (lastAccess.geo && currentAccess.geo) {
        const timeDiff = (currentAccess.timestamp - lastAccess.timestamp) / 1000 / 60 / 60;
        const distance = this.calculateDistance(
          lastAccess.geo.ll[0], lastAccess.geo.ll[1],
          currentAccess.geo.ll[0], currentAccess.geo.ll[1]
        );

        if (distance > 500 && timeDiff < 2) {
          anomalies.push('IMPOSSIBLE_TRAVEL');
        }
      }
    }

    // Check for unusual access time
    const hour = new Date().getHours();
    const usualHours = await this.redis.get(`admin:hours:${userId}`);
    if (usualHours && !JSON.parse(usualHours).includes(hour)) {
      anomalies.push('UNUSUAL_TIME');
    }

    // Check for new device/browser
    const knownAgents = await this.redis.smembers(`admin:agents:${userId}`);
    const agentHash = createHash('sha256').update(currentAccess.userAgent).digest('hex');
    if (knownAgents.length > 0 && !knownAgents.includes(agentHash)) {
      anomalies.push('NEW_DEVICE');
    }

    return { anomalies, riskScore: anomalies.length };
  }

  calculateDistance(lat1, lon1, lat2, lon2) {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon/2) * Math.sin(dLon/2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  }
}

