import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.servlet.*;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

@Configuration
@EnableWebSecurity
@EnableMethodSecurity(prePostEnabled = true)
public class ProductionAdminSecurityConfig {

    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final String ADMIN_PATH = System.getenv("ADMIN_SECRET_PATH");

    // IP whitelist from environment (comma-separated)
    private static final Set<String> ALLOWED_IPS = new HashSet<>(
        Arrays.asList(System.getenv("ADMIN_ALLOWED_IPS").split(","))
    );

    @Bean
    public SecurityFilterChain adminSecurityFilterChain(HttpSecurity http) throws Exception {
        http
            .securityMatcher("/" + ADMIN_PATH + "/**")
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/" + ADMIN_PATH + "/login").permitAll()
                .requestMatchers("/" + ADMIN_PATH + "/**").hasRole("ADMIN")
            )
            .formLogin(form -> form
                .loginPage("/" + ADMIN_PATH + "/login")
                .successHandler(new AdminAuthSuccessHandler())
                .failureHandler(new AdminAuthFailureHandler())
            )
            .logout(logout -> logout
                .logoutUrl("/" + ADMIN_PATH + "/logout")
                .logoutSuccessHandler(new AdminLogoutHandler())
                .deleteCookies("JSESSIONID", "ADMIN_SESSION")
                .invalidateHttpSession(true)
            )
            .sessionManagement(session -> session
                .sessionFixation().newSession()
                .maximumSessions(1)
                .maxSessionsPreventsLogin(true)
            )
            .headers(headers -> headers
                .frameOptions().deny()
                .xssProtection().block(true)
                .contentSecurityPolicy("default-src 'self'; script-src 'self'; style-src 'self'")
                .httpStrictTransportSecurity().maxAgeInSeconds(31536000).includeSubDomains(true)
            )
            .csrf(csrf -> csrf
                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
            );

        // Layer 1: IP Whitelist Filter
        http.addFilterBefore(new AdminIPWhitelistFilter(), 
                            UsernamePasswordAuthenticationFilter.class);

        // Layer 2: Rate Limiting Filter
        http.addFilterBefore(new AdminRateLimitFilter(),
                            AdminIPWhitelistFilter.class);

        return http.build();
    }

    // IP Whitelist Filter - First line of defense
    public class AdminIPWhitelistFilter implements Filter {
        @Override
        public void doFilter(ServletRequest request, ServletResponse response, 
                           FilterChain chain) throws IOException, ServletException {
            HttpServletRequest httpRequest = (HttpServletRequest) request;
            HttpServletResponse httpResponse = (HttpServletResponse) response;

            String clientIP = getClientIP(httpRequest);
            String requestPath = httpRequest.getRequestURI();

            if (requestPath.startsWith("/" + ADMIN_PATH)) {
                if (!ALLOWED_IPS.contains(clientIP)) {
                    // CRITICAL: Log unauthorized access attempt
                    auditLogger.warn("BLOCKED_ADMIN_ACCESS: IP={} Path={} UserAgent={}",
                        clientIP, requestPath, httpRequest.getHeader("User-Agent"));

                    // Alert security team for repeated attempts
                    SecurityAlertService.sendAlert(
                        "Unauthorized admin access attempt from " + clientIP);

                    // Return 404 to hide admin panel existence
                    httpResponse.sendError(HttpServletResponse.SC_NOT_FOUND);
                    return;
                }
                auditLogger.info("ADMIN_ACCESS_ALLOWED: IP={} Path={}", clientIP, requestPath);
            }
            chain.doFilter(request, response);
        }

        private String getClientIP(HttpServletRequest request) {
            String xForwardedFor = request.getHeader("X-Forwarded-For");
            if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
                return xForwardedFor.split(",")[0].trim();
            }
            return request.getRemoteAddr();
        }
    }

    // Rate Limiting Filter - Prevent brute force
    public class AdminRateLimitFilter implements Filter {
        private final RateLimiter rateLimiter = RateLimiter.create(5.0); // 5 requests per second
        private final Map<String, AtomicInteger> failedAttempts = new ConcurrentHashMap<>();

        @Override
        public void doFilter(ServletRequest request, ServletResponse response,
                           FilterChain chain) throws IOException, ServletException {
            HttpServletRequest httpRequest = (HttpServletRequest) request;
            HttpServletResponse httpResponse = (HttpServletResponse) response;
            String clientIP = httpRequest.getRemoteAddr();

            // Check for account lockout (5+ failed attempts)
            AtomicInteger attempts = failedAttempts.getOrDefault(clientIP, new AtomicInteger(0));
            if (attempts.get() >= 5) {
                auditLogger.error("ADMIN_LOCKOUT: IP={} exceeds max failed attempts", clientIP);
                httpResponse.sendError(HttpServletResponse.SC_TOO_MANY_REQUESTS,
                    "Account locked. Contact administrator.");
                return;
            }

            // Rate limiting
            if (!rateLimiter.tryAcquire()) {
                auditLogger.warn("RATE_LIMIT_EXCEEDED: IP={}", clientIP);
                httpResponse.sendError(HttpServletResponse.SC_TOO_MANY_REQUESTS);
                return;
            }

            chain.doFilter(request, response);
        }
    }
}
```

**MFA Implementation with TOTP**:

```java
import dev.samstevens.totp.code.*;
import dev.samstevens.totp.secret.DefaultSecretGenerator;
import org.springframework.stereotype.Service;

@Service
public class AdminMFAService {

    private final CodeVerifier verifier;
    private final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    public AdminMFAService() {
        this.verifier = new DefaultCodeVerifier(
            new DefaultCodeGenerator(), 
            new SystemTimeProvider()
        );
    }

    public boolean verifyTOTPCode(String username, String secret, String userCode) {
        boolean isValid = verifier.isValidCode(secret, userCode);

        if (isValid) {
            auditLogger.info("MFA_SUCCESS: user={}", username);
        } else {
            auditLogger.warn("MFA_FAILURE: user={} attempted_code={}", 
                username, userCode.substring(0, 2) + "****");
        }

        return isValid;
    }

    public String generateNewSecret() {
        return new DefaultSecretGenerator().generate();
    }
}

// Custom Authentication Provider requiring MFA
@Component
public class AdminMFAAuthenticationProvider implements AuthenticationProvider {

    @Autowired
    private AdminMFAService mfaService;

    @Autowired
    private AdminUserRepository userRepository;

    @Override
    public Authentication authenticate(Authentication authentication) 
            throws AuthenticationException {

        String username = authentication.getName();
        String password = authentication.getCredentials().toString();
        String totpCode = ((AdminAuthToken) authentication).getTotpCode();

        AdminUser user = userRepository.findByUsername(username)
            .orElseThrow(() -> new BadCredentialsException("Invalid credentials"));

        // Verify password
        if (!passwordEncoder.matches(password, user.getPasswordHash())) {
            throw new BadCredentialsException("Invalid credentials");
        }

        // CRITICAL: Verify MFA code
        if (!mfaService.verifyTOTPCode(username, user.getMfaSecret(), totpCode)) {
            throw new BadCredentialsException("Invalid MFA code");
        }

        return new UsernamePasswordAuthenticationToken(
            username, password, user.getAuthorities());
    }
}
